import java.util.ArrayList;
import java.util.List;
import java.util.TreeMap;

public class ScratchPad {

    public static void main(String[] args) {
        int[][] testTrips = {{0, 3}, {2, 7}, {2, 5}};
        int[][] result = overlapping(testTrips);

        for (int[] interval : result) {
            System.out.println(interval[0] + ", " + interval[1] + ", " + interval[2]);
        }
    }

    public static int[][] overlapping(int[][] trips) {
        if (trips.length == 0) return trips;

        List<int[]> res = new ArrayList<>();
        TreeMap<Integer, Integer> open = new TreeMap<>();
        TreeMap<Integer, Integer> close = new TreeMap<>();

        for (int[] t : trips) {
            open.put(t[0], open.getOrDefault(t[0], 0) + 1);
            close.put(t[1], close.getOrDefault(t[1], 0) + 1);
        }

        int start = open.firstKey();
        int cnt = open.get(start);
        open.remove(start);

        while (!open.isEmpty() || !close.isEmpty()) {
            if (!open.isEmpty() && (close.isEmpty() || open.firstKey() <= close.firstKey())) {
                if (open.firstKey() != close.firstKey()) {
                    res.add(new int[]{start, open.firstKey() - 1, cnt});
                }
                start = open.firstKey();
                cnt += open.get(start);
                open.remove(start);
            } else {
                res.add(new int[]{start, close.firstKey(), cnt});
                start = close.firstKey() + 1;
                cnt -= close.get(close.firstKey());
                close.remove(close.firstKey());
            }
        }

        return res.toArray(new int[res.size()][3]);
    }

    private static <K, V> V getOrDefault(TreeMap<K, V> map, K key, V defaultValue) {
        if (map.containsKey(key)) {
            return map.get(key);
        }
        return defaultValue;
    }
}


