class Interval {
    int start;
    int end;
    Interval() { start = 0; end = 0; }
    Interval(int s, int e) { start = s; end = e; }
    Interval(Interval interval) {
        this.start = interval.start;
        this.end = interval.end;
    }

    @Override public String toString() {
        return String.format("< %d, %d >", this.start, this.end);
    }
}

public class CountTrips {


    public void solveEasy(List<Interval> intervals) {
        int minStart = Integer.MAX_VALUE;
        int maxEnd = Integer.MIN_VALUE;

        for (Interval interval : intervals) {
            minStart = Math.min(minStart, interval.start);
            maxEnd = Math.max(maxEnd, interval.end);
        }

        int[] array = new int[maxEnd+1];
        Arrays.fill(array, 0);

        for (Interval interval : intervals) {
            for (int i = interval.start; i <= interval.end; i++) {
                array[i]++;
            }
        }

        Stack<Integer> s = new Stack<>();

        for (int i =0; i < array.length; i++) {
            if(array[i] != 0)
                s.push(i);
        }

        int count = array[s.peek()];

        while (!s.isEmpty()) {
            int start = s.peek();
            int end = s.peek();

            while (!s.isEmpty() && array[s.peek()] == count) {
                start = s.pop();
            }

            System.out.println(String.format("%d, %d : %d", start, end, count));

            if (!s.isEmpty())
                count = array[s.peek()];

        }

        System.out.println(Arrays.toString(array));
    }


    public void solve(List<Interval> intervals) {
        LinkedList<Pair<Interval, Integer>> ic = new LinkedList<>();

        PriorityQueue<Pair<Interval, Integer>> pq = new PriorityQueue<>(new Comparator<Pair<Interval, Integer>>() {

            @Override public int compare(Pair<Interval, Integer> i1, Pair<Interval, Integer> i2) {
                return i1.getLeft().start == i2.getLeft().start ? i1.getLeft().end - i2.getLeft().end : i1.getLeft().start - i2.getLeft().start;
            }
        });

        for (Interval interval : intervals)
            pq.add(Pair.of(interval, 1));

        ic.addLast(pq.poll());

        while(!pq.isEmpty()) {
            Pair<Interval, Integer> p1 = ic.pollLast();
            Interval i1 = p1.getLeft();

            Pair<Interval, Integer> p2 = pq.poll();
            Interval i2 = p2.getLeft();

            //System.out.println(String.format(" %d, %d, %d", p1.getLeft().start, p1.getLeft().end, p1.getRight()));

            if (i1.end < i2.start) { // no overlap
                ic.addLast(p1);
                ic.addLast(p2);
            } else if (i1.start == i2.start && i1.end == i2.end) {
                ic.addLast(Pair.of(new Interval(i1.start, i2.end), p1.getRight() + p2.getRight()));
            } else if (i1.start < i2.start) {
                ic.addLast(Pair.of(new Interval(i1.start, i2.start-1), p1.getRight()));
                pq.offer(Pair.of(new Interval(i2.start, i1.end), p1.getRight()));
                pq.offer(p2);
            } else{
                Interval overlap = new Interval(i1.start, Math.min(i1.end, i2.end));
                ic.addLast(Pair.of(overlap, p1.getRight() + p2.getRight()));
                int count = i1.end > i2.end ? p1.getRight() : p2.getRight();
                pq.offer(Pair.of(new Interval(overlap.end +1, Math.max(i1.end, i2.end)), count));
            }
        }

        while (!pq.isEmpty())
            ic.addLast(pq.poll());

        for(Pair<Interval, Integer> p : ic) {
            System.out.println(String.format(" %d, %d, %d", p.getLeft().start, p.getLeft().end, p.getRight()));
        }

    }

    public static void main(String[] args) {

        List<Interval> input = new ArrayList<>();


        input.add(new Interval(0,3));
