def count_overlap(intervals):
    moment_status = []
    for interval in intervals:
            moment_status.append((interval[0], 1)) #busy
            moment_status.append((interval[1], -1)) #no_busy

    moment_status.sort(key=lambda x:(x[0], -x[1]))
    start = moment_status[0][0]
    busy_count = 0
    res = [[start, start, 0]]
    for moment, busy in moment_status:
        if busy == 1:
            if moment > start:
                if busy_count != res[-1][-1]:
                    res.append([start, moment - 1, busy_count])
                    start = moment
                else:
                    res[-1][1] = moment
            busy_count += 1
        else:
            if moment >= start:
                if busy_count != res[-1][-1]:
                    res.append([start, moment, busy_count])
                else:
                    res[-1][1] = moment
                start = moment + 1
            busy_count -= 1  
    return res[1:]
